ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?core_courses WHERE {
  ?programs a :Programs .
  ?programs p:Core_Courses ?core_courses .
  ?programs p:ProgramName ?programname_f .
  FILTER(STR(?programname_f) = "Computer Science")
} }
  full: { SELECT ?core_courses ?electives WHERE {
  ?programs a :Programs .
  ?programs p:Core_Courses ?core_courses .
  ?programs p:Electives ?electives .
  ?programs p:ProgramName ?programname_f .
  FILTER(STR(?programname_f) = "Computer Science")
} }
  component_2: { SELECT ?electives WHERE {
  ?programs a :Programs .
  ?programs p:Electives ?electives .
  ?programs p:ProgramName ?programname_f .
  FILTER(STR(?programname_f) = "Computer Science")
} }
}

